PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?costume_supervisor ?costumes2 WHERE {
  ?costumes a :Costumes .
  ?costumes p:Costume_Supervisor ?costume_supervisor .
  ?costumes p:Costumes ?costumes2 .
  ?costumes p:Budget ?budget_f .
  FILTER(xsd:double(?budget_f) < 750000)
} }
  full: { SELECT ?costume_designer ?costume_supervisor ?costumes2 WHERE {
  ?costumes a :Costumes .
  ?costumes p:Costume_Designer ?costume_designer .
  ?costumes p:Costume_Supervisor ?costume_supervisor .
  ?costumes p:Costumes ?costumes2 .
  ?costumes p:Budget ?budget_f .
  FILTER(xsd:double(?budget_f) < 750000)
} }
  component_2: { SELECT ?costume_designer ?costumes2 WHERE {
  ?costumes a :Costumes .
  ?costumes p:Costume_Designer ?costume_designer .
  ?costumes p:Costumes ?costumes2 .
  ?costumes p:Budget ?budget_f .
  FILTER(xsd:double(?budget_f) < 750000)
} }
}

